import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a logarithm?", a: "A logarithm answers the question: what exponent is needed to get a number from a base? For example, log base 10 of 100 is 2 because 10^2 = 100." },
  { q: "What is the difference between log and ln?", a: "Log usually means base 10 in school and calculator contexts, while ln means natural log with base e. Both are logarithms, but they use different bases." },
  { q: "How do you calculate log base 2?", a: "Log base 2 can be calculated with the change-of-base formula: log2(x) = ln(x) / ln(2). It tells how many times 2 must be multiplied by itself to reach x." },
  { q: "What is an antilogarithm?", a: "An antilogarithm reverses a logarithm. If log base b of x equals y, then the antilog is b^y = x." },
  { q: "How are logarithms used in real life?", a: "Logarithms are used in sound levels, pH, earthquakes, computer science, finance, biology, and any situation where values grow or shrink across very large ranges." },
];

type Mode = "log" | "antilog";
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(10)).toLocaleString() : "Invalid";

export default function LogCalculator() {
  const [mode, setMode] = useState<Mode>("log");
  const [number, setNumber] = useState(100);
  const [base, setBase] = useState(10);
  const [antilogValue, setAntilogValue] = useState(2);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (base <= 0 || base === 1) return { label: "Invalid base", value: "Base must be positive and not equal to 1.", step: "A logarithm base must be greater than 0 and not equal to 1." };
    if (mode === "log") {
      if (number <= 0) return { label: "Invalid number", value: "Number must be greater than zero.", step: "Logarithms are defined for positive numbers in the real number system." };
      const value = Math.log(number) / Math.log(base);
      const name = base === Math.E ? "ln" : base === 10 ? "log10" : `log base ${base}`;
      return { label: name, value: fmt(value), step: `log_${base}(${number}) = ln(${number}) / ln(${base}) = ${fmt(value)}. This means ${base}^${fmt(value)} = ${number}.` };
    }
    const value = Math.pow(base, antilogValue);
    return { label: "Antilog Result", value: fmt(value), step: `Antilog base ${base} of ${antilogValue} = ${base}^${antilogValue} = ${fmt(value)}.` };
  }, [mode, number, base, antilogValue]);

  return (
    <>
      <SEOHead title="Free Log Calculator Online - Calculate Logarithm in Any Base Instantly | CalcHive" description="Free online logarithm calculator. Calculate log in any base including natural log ln and log base 10 with step by step solution instantly. 100% free for students, no signup required." canonical="/log-calculator" keywords="free log calculator, logarithm calculator free online, natural log calculator free, log base 10 calculator free, ln calculator free online" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Log Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this logarithm calculator free online to calculate log in any base, natural log ln, log base 10, and antilog results.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label htmlFor="log-mode" className="text-sm font-semibold text-foreground block mb-2">Mode</label><select id="log-mode" value={mode} onChange={(event) => setMode(event.target.value as Mode)} className={inputClass}><option value="log">Logarithm</option><option value="antilog">Antilog</option></select></div>
            <div><label htmlFor="log-base" className="text-sm font-semibold text-foreground block mb-2">Base</label><input id="log-base" type="number" inputMode="decimal" step="0.01" value={base} onChange={(event) => setBase(Number(event.target.value))} className={inputClass} /></div>
            {mode === "log" ? <div><label htmlFor="log-number" className="text-sm font-semibold text-foreground block mb-2">Number</label><input id="log-number" type="number" inputMode="decimal" value={number} onChange={(event) => setNumber(Number(event.target.value))} className={inputClass} /></div> : <div><label htmlFor="antilog-value" className="text-sm font-semibold text-foreground block mb-2">Log value</label><input id="antilog-value" type="number" inputMode="decimal" step="0.01" value={antilogValue} onChange={(event) => setAntilogValue(Number(event.target.value))} className={inputClass} /></div>}
          </div>
          <motion.div key={`${mode}-${number}-${base}-${antilogValue}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.label}</p><p className="text-5xl font-black text-white tracking-tight break-words" data-testid="result-log">{result.value}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Logarithms in Any Base for Free</h2><p className="text-muted-foreground leading-relaxed">Enter a positive number and a valid base. This free log calculator uses the change-of-base formula to calculate the logarithm instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">What is the Difference Between Log ln and Log Base 10</h2><p className="text-muted-foreground leading-relaxed">Log base 10 calculator free results use base 10, while natural log calculator free results use base e. Any base can be entered manually.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Logarithm Tool for Math and Science Students</h2><p className="text-muted-foreground leading-relaxed">Use this ln calculator free online for algebra, science, exponential growth, decay, and antilog checks.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/log-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


